import{_ as a,c as e,o as d,ag as r}from"./chunks/framework.dvv-DFtf.js";const u=JSON.parse('{"title":"MemX — AI 智能记忆管理","description":"","frontmatter":{},"headers":[],"relativePath":"memx/index.md","filePath":"memx/index.md","lastUpdated":1772252630000}'),n={name:"memx/index.md"};function o(i,t,s,l,h,p){return d(),e("div",null,[...t[0]||(t[0]=[r(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /memx.md for this page in Markdown format</div><h1 id="memx-—-ai-智能记忆管理" tabindex="-1">MemX — AI 智能记忆管理 <a class="header-anchor" href="#memx-—-ai-智能记忆管理" aria-label="Permalink to &quot;MemX — AI 智能记忆管理&quot;">​</a></h1><h2 id="什么是-memx" tabindex="-1">什么是 MemX？ <a class="header-anchor" href="#什么是-memx" aria-label="Permalink to &quot;什么是 MemX？&quot;">​</a></h2><p><strong>MemX</strong> 是 Lurus 推出的 GUI 化 AI 记忆管理产品，基于 <a href="https://github.com/UU114/memx" target="_blank" rel="noreferrer">ACE（Adaptive Context Engine）</a> 核心引擎构建。它为 AI Agent 提供完整的知识生命周期管理：<strong>智能提取 → 自动去重 → 时间衰减 → 混合召回</strong>，让 AI 拥有真正像人类一样的&quot;记忆力&quot;。</p><p>与传统的 AI 记忆系统相比，MemX 的核心优势在于：</p><ul><li><strong>极低 LLM 成本</strong>的知识提取 — 规则预筛减少 90%+ 的 LLM 调用</li><li><strong>仿生遗忘曲线</strong> — 重要知识越用越牢，过时知识自然淡出</li><li><strong>全链路隐私保护</strong> — 敏感信息永远不会进入向量数据库</li></ul><h2 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h2><h3 id="智能知识蒸馏" tabindex="-1">智能知识蒸馏 <a class="header-anchor" href="#智能知识蒸馏" aria-label="Permalink to &quot;智能知识蒸馏&quot;">​</a></h3><p>MemX 的 Reflector 引擎采用 hybrid 混合模式（规则预筛选 + LLM 精炼），从对话中自动识别 5 种知识模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td>错误修复</td><td>识别「报错 → 解决」模式</td><td>&quot;pytest 超时问题，改用 <code>-x</code> 参数解决&quot;</td></tr><tr><td>重试成功</td><td>检测反复尝试后的正确方案</td><td>&quot;第三次换用 <code>asyncio.gather</code> 终于跑通&quot;</td></tr><tr><td>配置变更</td><td>记录环境/配置修改</td><td>&quot;Redis 连接池从 10 调到 50&quot;</td></tr><tr><td>新工具使用</td><td>识别首次使用的工具或库</td><td>&quot;引入 <code>pydantic-settings</code> 管理配置&quot;</td></tr><tr><td>重复操作</td><td>检测高频重复的操作模式</td><td>&quot;每次部署都要手动清理缓存&quot;</td></tr></tbody></table><p>每条知识自动评分（0-100），低于阈值的噪音数据被过滤，只保留高价值知识。</p><h3 id="语义去重与冲突检测" tabindex="-1">语义去重与冲突检测 <a class="header-anchor" href="#语义去重与冲突检测" aria-label="Permalink to &quot;语义去重与冲突检测&quot;">​</a></h3><p>Curator 引擎通过余弦相似度自动处理重复知识：</p><ul><li><strong>相似度 ≥ 0.8</strong> → 自动合并，保留最优版本</li><li><strong>相似度 0.5-0.8</strong> → 标记为潜在冲突，等待用户确认</li><li><strong>相似度 &lt; 0.5</strong> → 视为独立知识</li></ul><h3 id="仿生记忆衰减" tabindex="-1">仿生记忆衰减 <a class="header-anchor" href="#仿生记忆衰减" aria-label="Permalink to &quot;仿生记忆衰减&quot;">​</a></h3><p>模拟人类记忆的自然遗忘曲线：</p><ul><li><strong>7 天保护期</strong> — 新知识不会被衰减</li><li><strong>指数衰减</strong> — 不被检索的知识逐步降低权重</li><li><strong>召回增强</strong> — 每次被检索到的知识获得权重加成</li><li><strong>永久记忆</strong> — 被检索 15 次以上的知识自动晋升，不再衰减</li></ul><h3 id="四层混合检索" tabindex="-1">四层混合检索 <a class="header-anchor" href="#四层混合检索" aria-label="Permalink to &quot;四层混合检索&quot;">​</a></h3><p>超越纯向量搜索的多层检索架构：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L1 精确匹配 → L2 模糊匹配 → L3 元数据匹配 → L4 向量语义搜索</span></span>
<span class="line"><span>        ↓           ↓            ↓              ↓</span></span>
<span class="line"><span>                ScoreMerger 加权融合</span></span>
<span class="line"><span>                        ↓</span></span>
<span class="line"><span>              DecayWeight × RecencyBoost × ScopeBoost</span></span>
<span class="line"><span>                        ↓</span></span>
<span class="line"><span>                    最终排序结果</span></span></code></pre></div><h3 id="隐私优先设计" tabindex="-1">隐私优先设计 <a class="header-anchor" href="#隐私优先设计" aria-label="Permalink to &quot;隐私优先设计&quot;">​</a></h3><p>12 种内置的不可绕过的隐私过滤规则，在任何知识写入前自动拦截：</p><ul><li>API Key（OpenAI / Anthropic / AWS / GitHub）</li><li>数据库连接串</li><li>PEM 私钥 / JWT Token</li><li>自定义正则规则（可扩展）</li></ul><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>说明</th></tr></thead><tbody><tr><td><strong>编程助手</strong></td><td>记住你的代码习惯、踩过的坑、项目约定</td></tr><tr><td><strong>客服系统</strong></td><td>积累客户历史交互知识，提供个性化服务</td></tr><tr><td><strong>个人知识库</strong></td><td>从日常对话中自动提炼和组织知识</td></tr><tr><td><strong>团队协作</strong></td><td>共享团队级记忆，新成员快速获取上下文</td></tr></tbody></table><h2 id="与传统记忆系统的对比" tabindex="-1">与传统记忆系统的对比 <a class="header-anchor" href="#与传统记忆系统的对比" aria-label="Permalink to &quot;与传统记忆系统的对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>传统方案 (mem0)</th><th>MemX (ACE)</th></tr></thead><tbody><tr><td>知识提取</td><td>LLM（每次 2-5K tokens）</td><td>hybrid 混合引擎（规则预筛 + LLM 精炼，减少 90%+ 调用）</td></tr><tr><td>去重</td><td>LLM 逐条判断</td><td>余弦相似度自动合并</td></tr><tr><td>遗忘</td><td>永久存储，无法淘汰</td><td>指数衰减 + 召回增强</td></tr><tr><td>搜索</td><td>仅向量搜索</td><td>四层混合搜索</td></tr><tr><td>隐私</td><td>无内置保护</td><td>12 种内置 PII 过滤</td></tr><tr><td>作用域</td><td>扁平（user / agent）</td><td>层级化（global / project / workspace）</td></tr><tr><td>Token 管理</td><td>调用方自行管理</td><td>内置预算裁剪（CJK 感知）</td></tr><tr><td>本地嵌入</td><td>需要 API</td><td>ONNX 本地推理，完全离线</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/memx/quickstart">快速开始</a> — 5 分钟体验 MemX 的核心功能</li><li><a href="/memx/concepts">核心概念</a> — 深入理解 ACE 引擎的设计原理</li><li><a href="/memx/architecture">架构设计</a> — 了解完整的系统架构</li><li><a href="/memx/faq">常见问题</a> — 使用中的常见问题解答</li></ul>`,29)])])}const m=a(n,[["render",o]]);export{u as __pageData,m as default};
